content:
## Actor

- id: {{ actor.id }}
- name: {{ actor.name }}
- description: {{ actor.description }}
- public state: {{ actor.public_state }}
- current activity: {{ actor.current_activity.name }}

## World

- id: {{ world.id }}
- name: {{ world.name }}
- language: {{ world.language }}

## Simulation

- id: {{ simulation.id }}
- current time: {{ simulation.current_time }}

## Location

- id: {{ location.id }}
- name: {{ location.name }}
- description: {{ location.description }}

## Actor inventory

{% for entry in inventory %}
- stack id: {{ entry.stack_id }}; item id: {{ entry.item_id }}; {{ entry.name }} x{{ entry.quantity }}{% if entry.quality %}; quality: {{ entry.quality }}{% endif %}; description: {{ entry.description }}
{% else %}
- none
{% endfor %}

## Actor equipment

{% for entry in equipment %}
- id: {{ entry.id }}; {{ entry.name }}; equipped: {{ entry.equipped }}{% if entry.equipped_position %}; position: {{ entry.equipped_position }}{% endif %}; description: {{ entry.description }}{% if entry.quality %}; quality: {{ entry.quality }}{% endif %}
{% else %}
- none
{% endfor %}

## Characters in the same location scope

{% for entry in perceived_characters %}
- id: {{ entry.character.id }}; name: {{ entry.character.name }}; location: {{ entry.location.name }}{% if entry.position %}; position: {{ entry.position }}{% endif %}{% if entry.landmark %}; landmark: {{ entry.landmark.name }}{% endif %}; public state: {{ entry.character.public_state }}; description: {{ entry.character.description }}
{% else %}
- none
{% endfor %}

## Background characters in this location

{% for entry in perceived_background_characters %}
- id: {{ entry.character.id }}; name: {{ entry.character.name }}; location: {{ entry.location.name }}{% if entry.position %}; position: {{ entry.position }}{% endif %}{% if entry.landmark %}; landmark: {{ entry.landmark.name }}{% endif %}; description: {{ entry.character.description }}
{% else %}
- none
{% endfor %}

## Item stacks in this location

{% for entry in perceived_items %}
- stack id: {{ entry.stack.id }}; item id: {{ entry.item.id }}; {{ entry.item.name }} x{{ entry.stack.quantity }}{% if entry.stack.quality %}; quality: {{ entry.stack.quality }}{% endif %}{% if entry.position %}; position: {{ entry.position }}{% endif %}{% if entry.owner_id %}; owner id: {{ entry.owner_id }}{% endif %}; description: {{ entry.item.description }}
{% else %}
- none
{% endfor %}

## Equipment in this location

{% for entry in perceived_equipment %}
- id: {{ entry.equipment.id }}; {{ entry.equipment.name }}{% if entry.position %}; position: {{ entry.position }}{% endif %}{% if entry.owner_id %}; owner id: {{ entry.owner_id }}{% endif %}; description: {{ entry.equipment.description }}{% if entry.equipment.quality %}; quality: {{ entry.equipment.quality }}{% endif %}
{% else %}
- none
{% endfor %}

## Containers in this location

{% for entry in perceived_containers %}
- id: {{ entry.container.id }}; {{ entry.container.name }}; state: {{ entry.container.state }}{% if entry.position %}; position: {{ entry.position }}{% endif %}{% if entry.owner_id %}; owner id: {{ entry.owner_id }}{% endif %}; description: {{ entry.container.description }}
{% else %}
- none
{% endfor %}

## Landmarks in this location

{% for landmark in perceived_landmarks %}
- id: {{ landmark.id }}; {{ landmark.name }}; description: {{ landmark.description }}
{% else %}
- none
{% endfor %}

## Deterministically segmented user input

{% for segment in input_segments %}
Segment {{ segment.index }}:
- type: {{ segment.type }}
{% if segment.type == "ooc" %}
- command text: {{ segment.command_text }}
{% endif %}
- source text:
{{ segment.source_text }}

{% else %}
No non-empty input segments were supplied.
{% endfor %}

## Raw user input

{{ user_input }}
